1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life", () => {
5	  it("should return empty set for empty grid", () => {
6	    expect(nextGeneration(new Set())).toEqual(new Set());
7	  });
8	  it("should return empty set for single living cell with no neighbors", () => {
9	    expect(nextGeneration(new Set(["0,0"]))).toEqual(new Set());
10	  });
11	  it("should kill a living cell with only one live neighbor", () => {
12	    expect(nextGeneration(new Set(["0,0", "1,0", "2,0"]))).not.toContain("0,0");
13	    expect(nextGeneration(new Set(["0,0", "1,0", "2,0"]))).not.toContain("2,0");
14	  });
15	  it("should keep a living cell alive with exactly two live neighbors", () => {
16	    expect(nextGeneration(new Set(["0,0", "1,0", "1,1"]))).toContain("1,0");
17	  });
18	  it("should keep a living cell alive with exactly three live neighbors", () => {
19	    expect(nextGeneration(new Set(["0,0", "1,0", "0,1", "1,1"]))).toContain("0,0");
20	  });
21	  it("should kill a living cell with four or more live neighbors", () => {
22	    // cell "1,1" has 4 live neighbors: "0,0", "1,0", "2,0", "0,1"
23	    expect(nextGeneration(new Set(["0,0", "1,0", "2,0", "0,1", "1,1"]))).not.toContain("1,1");
24	  });
25	  it("should bring a dead cell to life when it has exactly three live neighbors", () => {
26	    // dead cell "1,1" has exactly three live neighbors: "0,0", "1,0", "2,0"
27	    expect(nextGeneration(new Set(["0,0", "1,0", "2,0"]))).toContain("1,1");
28	  });
29	  it("should not bring a dead cell to life when it has fewer than three live neighbors", () => {
30	    // dead cell "1,1" has exactly two live neighbors: "0,0" and "1,0"
31	    expect(nextGeneration(new Set(["0,0", "1,0"]))).not.toContain("1,1");
32	  });
33	  it.todo("should not bring a dead cell to life when it has more than three live neighbors");
34	  it.todo("should handle a stable block pattern (2x2 square survives unchanged)");
35	});
