1	const getNeighbors = (cell: string): string[] => {
2	  const [x, y] = cell.split(",").map(Number);
3	  return [
4	    `${x - 1},${y - 1}`, `${x},${y - 1}`, `${x + 1},${y - 1}`,
5	    `${x - 1},${y}`,                        `${x + 1},${y}`,
6	    `${x - 1},${y + 1}`, `${x},${y + 1}`, `${x + 1},${y + 1}`,
7	  ];
8	};
9	
10	const countLiveNeighbors = (cell: string, liveCells: Set<string>): number =>
11	  getNeighbors(cell).filter(neighbor => liveCells.has(neighbor)).length;
12	
13	export function nextGeneration(cells: Set<string>): Set<string> {
14	  const next = new Set<string>();
15	
16	  for (const cell of cells) {
17	    const liveNeighborCount = countLiveNeighbors(cell, cells);
18	    if (liveNeighborCount >= 2 && liveNeighborCount <= 3) {
19	      next.add(cell);
20	    }
21	  }
22	
23	  const deadCandidates = new Set<string>();
24	  for (const cell of cells) {
25	    for (const neighbor of getNeighbors(cell)) {
26	      if (!cells.has(neighbor)) {
27	        deadCandidates.add(neighbor);
28	      }
29	    }
30	  }
31	
32	  for (const dead of deadCandidates) {
33	    if (countLiveNeighbors(dead, cells) === 3) {
34	      next.add(dead);
35	    }
36	  }
37	
38	  return next;
39	}
